#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        long long D[N];
        for (int i = 0; i < N; i++) {
            scanf("%lld", &D[i]);
        }
        long double depth[N];
        for (int i = 0; i < N; i++) {
            depth[i] = 0;
        }
        while (Q--) {
            int type;
            scanf("%d", &type);
            if (type == 1) {
                int x;
                long long v;
                scanf("%d %lld", &x, &v);
                x--;
                depth[x] += (long double)v / (long double)1;
                for (int i = 0; i < N; i++) {
                    if (depth[i] > D[i]) {
                        long double excess = depth[i] - D[i];
                        depth[i] = D[i];
                        if (i > 0) {
                            depth[i - 1] += excess / 2;
                        }
                        if (i < N - 1) {
                            depth[i + 1] += excess / 2;
                        }
                    }
                }
            } else {
                int x;
                scanf("%d", &x);
                x--;
                if (depth[x] > D[x]) {
                    printf("%.10Lf\n", D[x]);
                } else {
                    printf("%.10Lf\n", depth[x]);
                }
            }
        }
    }
    return 0;
}

