import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            long[] D = new long[N];
            for (int i = 0; i < N; i++) {
                D[i] = sc.nextLong();
            }
            double[] depth = new double[N];
            while (Q-- > 0) {
                int type = sc.nextInt();
                if (type == 1) {
                    int x = sc.nextInt() - 1;
                    long v = sc.nextLong();
                    depth[x] += (double)v;
                    for (int i = 0; i < N; i++) {
                        if (depth[i] > D[i]) {
                            double excess = depth[i] - D[i];
                            depth[i] = D[i];
                            if (i > 0) {
                                depth[i - 1] += excess / 2;
                            }
                            if (i < N - 1) {
                                depth[i + 1] += excess / 2;
                            }
                        }
                    }
                } else {
                    int x = sc.nextInt() - 1;
                    if (depth[x] > D[x]) {
                        System.out.println(D[x]);
                    } else {
                        System.out.println(depth[x]);
                    }
                }
            }
        }
    }
}

